import { describe, it, expect } from "vitest";
import { run } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial ---
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [] }] });
    expect(out).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per item type ---
  it("single plain sword (newcomer, first contract) yields base 100 + 10 first-insurance + 5 fee = 115 G", () => {
    const out = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single plain amulet (newcomer, first contract) yields base 60 + 6 first-insurance + 5 fee = 71 G (rounded up)");
  it.todo("single plain staff (newcomer, first contract) yields base 80 + 8 first-insurance + 5 fee = 93 G");
  it.todo("single plain potion (newcomer, first contract) yields base 40 + 4 first-insurance + 5 fee = 49 G");

  // --- Component base premiums and blocks ---
  it.todo("2 runes -> base premium 50 G (no block)");
  it.todo("3 runes -> base premium 60 G (block applies)");
  it.todo("4 runes -> base premium 100 G (no block; block requires exactly 3)");
  it.todo("7 runes -> base premium 175 G (no block; 7*25)");
  it.todo("2 runes + 1 moonstone -> base premium 75 G (alike = same type, no block)");
  it.todo("3 runes + 3 moonstones -> base premium 120 G (two separate blocks)");

  // --- Item-specific modifiers ---
  it.todo("cursed sword adds 50% of the sword's base premium");
  it.todo("enchantment exactly 5 triggers the 30% high-enchantment surcharge");
  it.todo("enchantment 4 does NOT trigger the high-enchantment surcharge");
  it.todo("cursed + enchantment 5 sword: both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years gets the 20% loyalty discount");
  it.todo("customer with <2 years does not get the loyalty discount");
  it.todo("each quote includes a 10% first-insurance surcharge per item");
  it.todo("second quote in scenario receives the 15% follow-up contract discount");

  // --- Processing fee + rounding direction ---
  it.todo("processing fee of 5 G is added after all other modifiers");
  it.todo("premium calculation of 197.5 G rounds up to 198 G");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet -> 210 G before further modifiers and fee (curse applies to sword only)");

  // --- Integration examples from the spec ---
  it.todo("newcomer with cursed steel sword enchant 3 -> premium 165 G");
  it.todo("long-standing customer's second contract with cursed sword enchant 7 -> premium 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, enchant 3) damage 500 -> payout 400 (minus 100 deductible)");
  it.todo("damage to a rune (insurance 250) of 200 -> payout 100 (minus 100 deductible)");

  // --- Claim: special clauses ---
  it.todo("dragon-material sword enchant 8 damage 1000 -> payout 400 (high-enchant clause then deductible)");
  it.todo("dragon-material sword enchant 9 damage 1000 -> payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword enchant 5 damage 800 -> payout 700 (full reimbursement, then deductible)");
  it.todo("steel sword enchant 9 damage 1000 -> payout 400 (high-enchant clause then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword 500 + amulet 300 -> total payout 600 (deductible per item)");

  // --- Claim: cap rules ---
  it.todo("policy of sword + amulet -> insurance sum 1600, cap 3200");
  it.todo("cursed sword -> cap stays 2000 (premium modifiers don't raise cap)");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 (block affects premium only)");
  it.todo("sword cap 2000 with two 1500 claims -> first payout 1400 remaining 600, second payout 600 remaining 0");

  // --- Claim: rounding direction (in MHPCO's favor) ---
  it.todo("payout calculation of 350.5 rounds down to 350");

  // --- Multiple items of the same type ---
  it.todo("policy of two swords -> insurance sum 2000 and cap 4000");
  it.todo("two-sword policy with damages to both swords -> each damage gets its own deductible");
  it.todo("claim references more items of a type than insured -> CLI exits non-zero");

  // --- Error cases ---
  it.todo("quote with unknown item type -> CLI exits non-zero and writes error to stderr");
  it.todo("claim references item not in policy -> CLI exits non-zero and writes error to stderr");
  it.todo("claim damage entry with negative amount -> CLI exits non-zero and writes error to stderr");

  // --- CLI integration smoke test ---
  it.todo("schema example: amulet quote + 200 G fire damage claim returns expected results array");
});

