const BLOCK_BASE = 60;
const COMPONENT_TYPES = new Set(["rune"]);

const itemBaseTotal = (items: Item[]): number => {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += basePremium(item);
    }
  }
  for (const count of Object.values(componentCounts)) {
    total += count === 3 ? BLOCK_BASE : count * 25;
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const itemTotal = itemBaseTotal(items) * FIRST_INSURANCE_MULTIPLIER;
  return roundUp(itemTotal + PROCESSING_FEE);
};

