type Damage = { itemType: string; amount: number };
type Incident = { cause: string; damages: Damage[] };
type ClaimStep = { op: "claim"; policy: number; incident: Incident };
type Step = QuoteStep | ClaimStep;
type Scenario = { customer: Customer; steps: Step[] };

type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

// --- Pricing constants ---
const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOWUP_DISCOUNT = 0.15;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const BLOCK_BASE = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const DEDUCTIBLE = 100;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;

const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const groupBasePrice = (type: string, count: number): number => {
  const lineTotal = basePremium({ type }) * count;
  const blockApplies = COMPONENT_TYPES.has(type) && count === 3;
  return blockApplies ? BLOCK_BASE : lineTotal;
};

const itemBaseTotal = (items: Item[]): number =>
  Object.entries(countByType(items)).reduce(
    (sum, [type, count]) => sum + groupBasePrice(type, count),
    0,
  );

const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
  {
    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
    rate: HIGH_ENCHANTMENT_SURCHARGE,
  },
];

const itemSurchargeRate = (item: Item): number =>
  SURCHARGE_RULES.reduce((rate, rule) => (rule.applies(item) ? rate + rule.rate : rate), 0);

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremium(item) * itemSurchargeRate(item), 0);

const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
  let rate = 0;
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
  if (quoteIndex > 0) rate -= FOLLOWUP_DISCOUNT;
  return rate;
};

const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
  const baseTotal = itemBaseTotal(items);
  const firstInsurance = baseTotal * FIRST_INSURANCE_SURCHARGE;
  const policyModifier = baseTotal * policyModifierRate(customer, quoteIndex);
  const beforeFee = baseTotal + firstInsurance + itemSurcharges(items) + policyModifier;
  return roundUp(beforeFee + PROCESSING_FEE);
};

type Policy = { items: Item[]; capRemaining: number };

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);

const newPolicy = (items: Item[]): Policy => ({
  items,
  capRemaining: 2 * insuranceSum(items),
});

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const settleClaim = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
  const payout = incident.damages.reduce((sum, damage) => sum + damagePayout(damage), 0);
  const updated: Policy = { ...policy, capRemaining: policy.capRemaining - payout };
  return { result: { payout, remainingCap: updated.capRemaining }, policy: updated };
};

export const run = (scenario: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push({ premium: quotePremium(step.items, scenario.customer, policies.length) });
      policies.push(newPolicy(step.items));
    } else {
      const { result, policy } = settleClaim(policies[step.policy], step.incident);
      policies[step.policy] = policy;
      results.push(result);
    }
  }
  return { results };
};

