122	const policyDiscountRate = (customer: Customer, quoteIndex: number): number =>
123	  POLICY_DISCOUNT_RULES.reduce(
124	    (rate, rule) => (rule.applies(customer, quoteIndex) ? rate + rule.rate : rate),
125	    0,
126	  );
