165	const validateIncident = (policy: Policy, incident: Incident): void => {
166	  for (const damage of incident.damages) {
167	    if (damage.amount < 0) {
168	      throw new Error(`damage amount must be non-negative, got ${damage.amount}`);
169	    }
170	  }
171	  const insuredCounts = countByType(policy.items, "type");
172	  const damageCounts = countByType(incident.damages, "itemType");
173	  for (const [type, count] of Object.entries(damageCounts)) {
174	    const insured = insuredCounts[type] ?? 0;
