193	const settleClaim = (
194	  policy: Policy,
195	  incident: Incident,
196	): { result: ClaimResult; policy: Policy } => {
197	  validateIncident(policy, incident);
198	  const payout = Math.floor(Math.min(uncappedPayout(policy, incident), policy.capRemaining));
199	  const capRemaining = policy.capRemaining - payout;
200	  return { result: { payout, remainingCap: capRemaining }, policy: { ...policy, capRemaining } };
201	};
